async function loadStatus(){const app=document.querySelector("#app");try{const status=await window.go.main.App.Status();app.innerHTML=`<main class="shell"><aside class="nav"><div class="brand">Phone Task Client</div><button class="nav-item active">运行面板</button><button class="nav-item">全局配置</button><button class="nav-item">用户管理</button><button class="nav-item">API 模板</button><button class="nav-item">任务模板</button><button class="nav-item">历史任务</button></aside><section class="content"><header class="topbar"><div><h1>${status.name}</h1><p>${status.description}</p></div><span class="badge">${status.runtime}</span></header><section class="metrics"><div class="metric"><span>核心状态</span><strong>${status.coreReady?"可用":"未就绪"}</strong></div><div class="metric"><span>本地存储</span><strong>${status.storage}</strong></div><div class="metric"><span>设备池</span><strong>共享容量</strong></div></section><section class="panel"><h2>当前可用入口</h2><p>CLI 已支持发码、收码、TXT/API 来源、共享设备池、状态恢复、暂停/继续/停止和失败导出。UI 页面将在该 Wails 壳上继续接入同一套核心能力。</p><code>phone-task-client-windows-amd64.exe -mode receive -phone-source txt -input phones.txt</code></section></section></main>`}catch(error){app.innerHTML=`<pre class="error">${String(error)}</pre>`}}loadStatus();
